external_knowledge:
- "valuable stars" refers to players with a high market value;
- "numbers in the Fantasy Premier League game" refers to the total FPL points a player has;
- "worth more than fifty million" indicates players with a market value above 50 million;
- "top five performers" means the players with the highest FPL points.

sql:
SELECT COUNT(*) AS big_english_clubs
FROM clubs
WHERE big_club = 1 AND country = 'England';

SELECT name, fpl_value
FROM players
ORDER BY fpl_value DESC;

SELECT COUNT(*) AS total_players_under_20_with_goals
FROM players
WHERE age < 20 AND goals >= 1;

SELECT COUNT(*) AS count_players
FROM players
WHERE age >= 25 AND age < 30 AND position_cat = 2;
